 namespace WPAICG\Speech; use WPAICG\Speech\AIPKit_TTS_Provider_Strategy_Factory; use WPAICG\aipkit_dashboard; use WPAICG\AIPKit_Providers; use WPAICG\Chat\Utils\Utils as ChatUtils; use WP_Error; if (!defined('ABSPATH')) { exit; } class AIPKit_Speech_Manager { public function __construct() { if (!class_exists(ChatUtils::class)) { $utils_path = WPAICG_PLUGIN_DIR . 'classes/chat/utils/class-aipkit_chat_utils.php'; if (file_exists($utils_path)) { require_once $utils_path; } } } public function init_hooks() { } public function text_to_speech(string $text, array $options = []): string|WP_Error { $provider = $options['provider'] ?? null; $voice_id = $options['voice'] ?? null; $elevenlabs_model_id = ($provider === 'ElevenLabs' && isset($options['elevenlabs_model_id'])) ? $options['elevenlabs_model_id'] : null; $openai_model_id = ($provider === 'OpenAI' && isset($options['openai_model_id'])) ? $options['openai_model_id'] : null; if (empty($provider) || empty($voice_id)) { return new WP_Error('missing_tts_options', __('TTS Provider and Voice ID are required.', 'gpt3-ai-content-generator')); } if (empty($text)) { return new WP_Error('empty_tts_text', __('Text cannot be empty for speech generation.', 'gpt3-ai-content-generator')); } if (class_exists(ChatUtils::class)) { $cleaned_text = ChatUtils::aipkit_clean_text_for_tts($text); if (empty($cleaned_text)) { return new WP_Error('empty_cleaned_tts_text', __('Text became empty after cleaning formatting.', 'gpt3-ai-content-generator')); } } else { $cleaned_text = $text; } $strategy = AIPKit_TTS_Provider_Strategy_Factory::get_strategy($provider); if (is_wp_error($strategy)) { return $strategy; } $api_params = []; if (!class_exists(\WPAICG\AIPKit_Providers::class)) { $providers_path = WPAICG_PLUGIN_DIR . 'classes/dashboard/class-aipkit_providers.php'; if (file_exists($providers_path)) { require_once $providers_path; } else { return new WP_Error('dependency_missing', __('Internal configuration error (Providers).', 'gpt3-ai-content-generator')); } } $provider_data = AIPKit_Providers::get_provider_data($provider); $api_params['api_key'] = $provider_data['api_key'] ?? null; $api_params['base_url'] = $provider_data['base_url'] ?? null; $api_params['api_version'] = $provider_data['api_version'] ?? null; if (empty($api_params['api_key'])) { return new WP_Error('missing_api_key', sprintf(__('API Key for %s provider is missing in main settings.', 'gpt3-ai-content-generator'), $provider), ['status' => 500]); } $synthesis_options = [ 'voice' => $voice_id, 'format' => $options['format'] ?? 'mp3', ]; if ($provider === 'ElevenLabs' && !empty($elevenlabs_model_id)) { $synthesis_options['model_id'] = $elevenlabs_model_id; } if ($provider === 'OpenAI' && !empty($openai_model_id)) { $synthesis_options['model_id'] = $openai_model_id; } if ($provider === 'OpenAI' && isset($options['speed'])) { $synthesis_options['speed'] = $options['speed']; } $result = $strategy->generate_speech($cleaned_text, $api_params, $synthesis_options); if (is_wp_error($result)) { return $result; } return $result; } } 